  1	import React, { FC, useState } from 'react';
  2	import { useHistory } from 'react-router';
  3	import NodeNetworkConfigurationPolicyModel from 'src/console-models/NodeNetworkConfigurationPolicyModel';
  4	import { asAccessReview, getResourceUrl } from 'src/utils/helpers';
  5	import { useNMStateTranslation } from 'src/utils/hooks/useNMStateTranslation';
  6	
  7	import { useAccessReview } from '@openshift-console/dynamic-plugin-sdk';
  8	import { V1NodeNetworkConfigurationPolicy } from '@types';
  9	import ActionsDropdown from '@utils/components/ActionsDropdown/ActionsDropdown';
 10	import Loading from '@utils/components/Loading/Loading';
 11	
 12	import DeleteModal from '../components/DeleteModal';
 13	import EditModal from '../components/EditModal';
 14	import { isPolicySupported } from '../utils';
 15	
 16	import { getEditDescrition } from './utils';
 17	
 18	type PolicyActionsProps = {
 19	  policy: V1NodeNetworkConfigurationPolicy;
 20	  isKebabToggle?: boolean;
 21	  isPolicyArchived?: boolean | undefined;
 22	};
 23	
 24	const PolicyActions: FC<PolicyActionsProps> = ({ policy, isKebabToggle }) => {
 25	  const history = useHistory();
 26	  const formSupported = isPolicySupported(policy);
 27	  const { t } = useNMStateTranslation();
 28	  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
 29	  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
 30	
 31	  const [canUpdatePolicy] = useAccessReview({
 32	    verb: 'update',
 33	    resource: NodeNetworkConfigurationPolicyModel.plural,
 34	  });
 35	
 36	  const [canDeletePolicy] = useAccessReview({
 37	    verb: 'delete',
 38	    resource: NodeNetworkConfigurationPolicyModel.plural,
 39	  });
 40	
 41	  const onEditModalToggle = () => {
 42	    if (formSupported) return setIsEditModalOpen(true);
 43	
 44	    const policyDetailPage = getResourceUrl({
 45	      model: NodeNetworkConfigurationPolicyModel,
 46	      resource: policy,
 47	    });
 48	
 49	    history.push(`${policyDetailPage}/yaml`);
 50	  };
 51	
 52	  const onDeleteModalToggle = () => {
 53	    setIsDeleteModalOpen(true);
 54	  };
 55	
 56	  const actions = [
 57	    {
 58	      accessReview: asAccessReview(NodeNetworkConfigurationPolicyModel, policy, 'update'),
 59	      cta: onEditModalToggle,
 60	      id: 'edit-policy',
 61	      label: t('Edit'),
 62	      description: getEditDescrition(formSupported, canUpdatePolicy),
 63	    },
 64	    {
 65	      accessReview: asAccessReview(NodeNetworkConfigurationPolicyModel, policy, 'delete'),
 66	      cta: onDeleteModalToggle,
 67	      id: 'delete-policy',
 68	      label: t('Delete'),
 69	      description: canDeletePolicy === false && t('Cannot delete in view-only mode'),
 70	    },
 71	  ];
 72	
 73	  if (!policy) return <Loading />;
 74	
 75	  return (
 76	    <>
 77	      <ActionsDropdown
 78	        actions={actions}
 79	        id="virtual-machine-instance-migration-actions"
 80	        isKebabToggle={isKebabToggle}
 81	      />
 82	      {policy && isEditModalOpen && (
 83	        <EditModal
 84	          isOpen={isEditModalOpen}
 85	          closeModal={() => setIsEditModalOpen(false)}
 86	          policy={policy}
 87	        />
 88	      )}
 89	      {policy && isDeleteModalOpen && (
 90	        <DeleteModal
 91	          isOpen={isDeleteModalOpen}
 92	          closeModal={() => setIsDeleteModalOpen(false)}
 93	          policy={policy}
 94	        />
 95	      )}
 96	    </>
 97	  );
 98	};
 99	
100	export default PolicyActions;

